"""
MKT Original Language Commentary — 2 Kings chapters 4–5
Run: python3 scripts/zc-original-2kings-4-5.py

Source data used:
- data/interlinear/2kings.json
- data/translation/glossary-hebrew.json (key terms)
- data/translation/draft/mediating/2kings.json (MKT text)
- data/commentary/mkt-original/2kings.json (existing entries for continuity)

Key decisions in this range:
- ch. 4: The Shunammite's triple šālôm (vv22-26) is discussed at v26 — her responses
  are statements of faith, not deception; the Hebrew needs explanation
- ch. 4:34: gāḥar is a biblical hapax — noted at that verse
- ch. 4:35: zārar (sneeze) is a biblical hapax — noted at that verse
- ch. 5:14: ṭāḇal (dip/immerse) distinguished from rāḥaṣ (wash) — the immersion
  language is distinct from the washing instruction in v10; both terms tracked
- ch. 5:17: ʾădāmāh vs. ʾereṣ — Naaman requests soil (ʾădāmāh), not just "earth";
  the covenant-soil concept is significant
- ch. 5:27: dāḇaq (cling) carries covenant weight; the irony of its use here noted
- Transliteration style follows existing 2 Kings original entries: voweled academic
  form with <em> tags
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS2 = {
  "4": {
    "1": '<p><strong>nᵉšî ʾîš</strong> — "the wife of a man (of)": the phrase identifies her entirely by her relation to her dead husband, a member of the prophetic community (<em>bᵉnê hannᵉḇiʾîm</em>). Her direct appeal — "you know that your servant feared (<em>yārēʾ</em>) the LORD" — invokes the covenant connection between prophetic piety and prophetic responsibility. The creditor (<em>nōšeh</em>, from H5383 — to lend on interest, with the social weight of Lev 25:39-41) can legally enslave children for unpaid debt; the social background is attested in Neh 5:5. The widow has a legal problem only a prophet can solve.</p>',
    "2": '<p><strong>ʾăsûḵ šemen</strong> — "a jar of oil." The word <em>ʾāsûḵ</em> (H610) is rare — a small vessel for anointing oil, insufficient for cooking or commerce. The MKT\'s "jar" captures the sense; but the Hebrew emphasizes smallness and singularity: she has exactly nothing useful except this one anointing flask. The miracle proceeds not from abundance but from the scarcest possible resource — a pattern recurrent in the Elisha cycle (ch. 4:42-44; 2 Kgs 3:17) and deliberate: the prophet multiplies what the petitioner offers, not what he carries.</p>',
    "3": '<p><strong>kēlîm rêqîm</strong> — "empty vessels." The adjective <em>rêq</em> (H7386 — empty, hollow, vain) is the same word used in Gen 37:24 for the empty pit into which Joseph was thrown. The instruction to gather <em>many</em> empty vessels before any miracle has begun is a faith requirement: the quantity of vessels gathered limits the quantity of oil received (v6 confirms this). The negative command "do not get too few" (<em>ʾal tamʿîṭû</em>) suggests the disciples\' tendency to underestimate.</p>',
    "4": '<p><strong>sāgᵉrî haddālet baʿăḏēḵ</strong> — "shut the door behind you." The instruction is repeated in v5 as the action is performed. Elisha himself is absent from the miracle; the widow and her sons pour oil in private, behind a closed door. The prophetic miracle requires neither the prophet\'s presence nor a public audience — the <em>sāgar</em> (shut/close) emphasizes enclosure and exclusivity. This private modality contrasts with Elijah\'s confrontational, public miracles and anticipates Jesus\'s instruction to pray in the inner room with the door shut (Matt 6:6).</p>',
    "5": '<p><strong>wayyagsîšû ʾēlehā... wᵉhîʾ mōṣāqet</strong> — "they kept bringing her vessels... and she kept pouring." The verb <em>yāṣaq</em> (H3332, pour out) is an imperfect/continuous form here; the Hebrew syntax places her continuous pouring against their continuous bringing. The miracle operates dynamically in the act of pouring — not in the original jar — and ceases only when the vessels run out. The oil flows not from a store but from a divine provision activated by the act of faith.</p>',
    "6": '<p><strong>wayyaʿᵃmod haššāmen</strong> — "the oil stopped." The verb <em>ʿāmaḏ</em> (H5975, stand/stop) is the same used for the Jordan waters "standing" at the crossing (Josh 3:16). When the last vessel fills, the oil stops — not before, not after. The miracle is precisely calibrated to available capacity: the widow\'s faith in gathering vessels determines the scope of the miracle. The theological implication is that the limit was not in the oil (divine supply) but in the containers gathered (human preparation).</p>',
    "7": '<p><strong>šallᵉmî ʾet nᵉšēḵî</strong> — "pay your debt." The verb <em>šālem</em> (H7999 — pay, complete, make šālôm) connects the economic resolution to the broader šālôm theme of the passage. Elisha\'s instruction is practical and complete: sell the oil, pay the debt (<em>nāšeḵî</em> — literally "your bite/interest," from the same root as the creditor\'s title), and live on the surplus. The miracle produces enough to resolve the crisis and sustain the family — no surplus beyond need, but precisely sufficient.</p>',
    "8": '<p><strong>ʾiššāh gᵉḏôlāh</strong> — "a great/wealthy woman." The phrase uses <em>gāḏôl</em> (H1419 — great) without specifying in what respect; in context it suggests both social standing and wealth. The verb <em>ḥāzaq</em> (H2388 — seize, urge strongly) describes her compelling Elisha to eat: she does not merely invite but presses (<em>wayyiḥzaq ʿālāyw</em>). The regularity is established: "whenever he passed (<em>kol-pāʿam</em>, every time he passed), he turned in there to eat." The initiative is entirely hers.</p>',
    "9": '<p><strong>ʾîš ʾĕlōhîm qāḏôš</strong> — "a holy man of God." The title <em>qāḏôš</em> (H6918 — holy, set apart) is remarkable: this is the only occurrence in the Kings narrative where a human figure is called "holy" outright. The Shunammite\'s perception ("I perceive," <em>yāḏaʿtî</em>, perfect — I know with certainty) is theological discernment, not social observation. The verb <em>ʿābar</em> (pass through, H5674) in the participle <em>ʿōḇēr</em> + <em>tāmîḏ</em> (continually, H8548) establishes the regularity of the prophetic presence she has recognized and serves.</p>',
    "10": '<p>The four items — bed (<em>miṭṭāh</em>), table (<em>šulḥān</em>), chair (<em>kissēʾ</em>), and lamp (<em>mᵉnôrāh</em>) — constitute the minimal furniture for a functional room: sleep, eating, seating, and light. The lamp (<em>mᵉnôrāh</em>) is the same word used for the tabernacle lampstand (Exod 25:31ff); its inclusion in the list may not be incidental. The room is called a <em>ʿăliyyāh</em> (H5944 — upper room, roof chamber) — the word for the upper room in which Christ holds his final Passover (Mark 14:15; Luke 22:12) and where the disciples gather at Pentecost (Acts 1:13).</p>',
    "11": '<p><strong>wayyānāḥ šāmmāh</strong> — "he rested there." The verb <em>nûaḥ</em> (H5117 — rest, settle) describes Elisha\'s use of the room prepared for him. The Shunammite\'s gift of restful hospitality — a private space for the prophet — is rewarded with the miraculous provision of a son. The structural parallel to Abraham and Sarah (three visitors, a son promised — Gen 18) is made explicit in v16. Rest precedes revelation.</p>',
    "12": '<p>Elisha communicates with the Shunammite through his servant Gehazi — a distance mediated by hierarchy. The use of <em>šālaḥ</em> (send) and the summons through Gehazi suggests that Elisha observes prophetic decorum with respect to an unrelated married woman. When the Shunammite "stands before him" (<em>waqqāmet lᵉpānāyw</em>), the phrase echoes royal/court language: standing before a superior.</p>',
    "13": '<p><strong>ḥāradtî ʾēlênû</strong> — "you have gone to all this trouble for us." The verb <em>ḥāraḏ</em> (H2729 — tremble, be anxious, exert oneself) in the Hiphil indicates the care and effort she has taken. Her response — "I live among my own people" (<em>bᵉtôḵ ʿammî ʾānōḵî yōšābet</em>) — uses <em>tāwek</em> (midst/among) with <em>ʿam</em> (people/kinship group): she is embedded in her social network and does not need royal patronage. The answer is a gracious but clear statement of self-sufficiency.</p>',
    "14": '<p>Gehazi\'s observation — "she has no son and her husband is old" (<em>bēn ʾên lāh wᵉʾîšāh zāqēn</em>) — uses <em>zāqēn</em> (H2205 — old, elder) for the aged husband, the same word used for Abraham\'s advanced age in the son-of-promise narratives (Gen 18:11; 24:1). The barrenness-and-aged-husband combination places this narrative deliberately in the succession of promised-birth stories: Sarah, Rebekah, Rachel, Hannah. The verbal echoes signal that what follows will be another case of divine provision against biological impossibility.</p>',
    "15": '<p>She stands in the doorway (<em>bappetaḥ</em> — at the opening/threshold) rather than entering: the threshold marks a boundary of appropriate social access. Her position at the threshold mirrors the social negotiation of the entire episode — hospitality and honor-distance operating simultaneously.</p>',
    "16": '<p><strong>ḥōḇeqet bēn</strong> — "embracing a son." The verb <em>ḥāḇaq</em> (H2263 — to embrace, clasp) is the specific word for the physical embrace of a child; it appears in Song 2:6; 8:3 and Gen 33:4 for familial embrace. The announcement — "at this season (<em>kāʿēt ḥayyāh</em>)" — uses the same phrase as Gen 18:10 when YHWH announces Isaac\'s birth to Abraham and Sarah ("at this season of life/next year"). <em>ḥayyāh</em> (H2416) may mean "next year" or "in the season of living/spring." The verbal echo to the Genesis annunciation is exact and deliberate.</p>',
    "17": '<p>The fulfillment — "she conceived and bore a son at that season the following year" — uses <em>kāʿēt ḥayyāh</em> again (fulfilling the exact phrase of the announcement, v16) and the verb <em>yālaḏ</em> (bear, H3205). The <em>kāʾăšer dibbēr</em> ("just as [Elisha] had spoken") uses the standard formula for prophetic fulfillment, confirming that the announcement was a prophetic word, not merely a social prediction.</p>',
    "18": '<p>The transition <em>wayyigdal hayyeleḏ</em> — "the child grew" — is the standard growth formula of OT narrative (Gen 21:8; 1 Sam 2:21); it moves the narrative forward to the crisis. <em>ḥōṣᵉrîm</em> (H2784 — reapers) identifies the season (harvest) and the social setting (agricultural labor) of the child\'s illness.</p>',
    "19": '<p><strong>rōʾšî rōʾšî</strong> — "my head, my head!" The doubled form expresses intensity and urgency; the repetition is a child\'s distress call. The description is consistent with heatstroke (harvest, midday heat). The father\'s immediate delegation to the mother — not an attempt at treatment himself — shows the mother\'s centrality to this narrative.</p>',
    "20": '<p><strong>wayyāmot baṣṣohŏrāyim</strong> — "he died at noon." The death is stated simply, without euphemism, with a specific time. Noon (<em>ṣohŏrāyim</em>) reinforces the heat-narrative. The directness of <em>wayyāmot</em> (H4191, and he died) after the doubled cry of distress creates a stark, unambiguous statement of the crisis that the rest of the chapter resolves.</p>',
    "21": '<p><strong>wayyaššiḵēhû ʿal miṭṭat ʾîš hāʾĕlōhîm</strong> — "she laid him on the bed of the man of God." This is the Shunammite\'s first act, before summoning a donkey or telling her husband. Placing the dead child on the prophet\'s bed is an act of faith that the prophet\'s connection to YHWH extends even to death. The shut door (<em>wayyisgor baddᵉlet baʿăḏô</em>) seals the dead child in the prophetic space — echoing the shut door of the oil miracle (v4-5), where enclosure preceded supernatural provision.</p>',
    "22": '<p>The Shunammite requests a donkey and a servant to go to the man of God — without explaining why. Her husband\'s question ("why go today?") treats the journey as irregular: it is not a festival day (<em>rōʾš ḥōḏeš</em>, new moon) or Sabbath, the usual days for visiting a prophet. Her answer — <em>šālôm</em> — is the first of three instances in this passage where she uses the peace-formula while facing disaster.</p>',
    "23": '<p><strong>šālôm</strong> (first use in this passage). The word carries the full weight of covenantal "all is well" — wholeness, completion, soundness. The Shunammite says <em>šālôm</em> when the situation is anything but well: her son is dead. This is not deception but a theological statement — she trusts YHWH\'s governance and refuses to frame the situation as final before the prophet has responded. The grammar supports this: she does not say "it was šālôm"; she says "šālôm" as a present-tense declaration.</p>',
    "24": '<p><strong>ʿeṣôr wᵉlōʾ taʿᵃṣar lî lirkōb</strong> — "drive on and do not slow down for me to ride." The causative phrase is urgent: the Shunammite commands haste and forbids any deceleration on her account. <em>ʿāṣar</em> (H6113 — restrain, hold back) appears twice in two clauses. The urgency of her journey is expressed through repeated negatives of restraint: do not slow down unless I tell you.</p>',
    "25": '<p><strong>hinnēh haššûnammît hallezyāh</strong> — "there is the Shunammite woman!" Elisha\'s perception of her approach from a distance (<em>mērāḥôq</em>) before her arrival establishes his awareness of the situation. The exclamatory <em>hinnēh</em> (behold) signals dramatic recognition. He sends Gehazi to meet her — but the Shunammite will bypass the intermediary to reach the prophet himself (v27).</p>',
    "26": '<p>Gehazi\'s three-question greeting — "is it well (<em>šālôm</em>) with you? well with your husband? well with your child?" — probes the situation systematically. The Shunammite answers the entire triple question with one word: <em>šālôm</em>. This is the third šālôm in the passage (see vv22-23). The Hebrew reads <em>wayyōʾmer šālôm</em> — "and she said: peace." She has not abandoned grief (v27 shows her <em>mar nāpeš</em> — bitter of soul), but she refuses to articulate the crisis to Gehazi; she will speak only to the prophet who has the authority to act.</p>',
    "27": '<p><strong>mar nāpeš</strong> — "bitter of soul/spirit." <em>Mar</em> (H4751 — bitter) + <em>nāpeš</em> (H5315 — self/soul/breath/life) is the Hebrew idiom for intense anguish; the same phrase describes Hannah\'s grief (1 Sam 1:10) and Job\'s (Job 3:20; 7:11). The admission that follows — "YHWH has hidden it from me and has not told me" (<em>YHWH hisᵉtîr mimmennî wᵉlōʾ higgîḏ lî</em>) — is a candid acknowledgment of prophetic limitation: the man of God does not have omniscient access to all divine purposes. H6845 (<em>sātar</em>, conceal) in the Hiphil: YHWH deliberately concealed this from Elisha.</p>',
    "28": '<p><strong>hăšāʾaltî bēn mēʾēt ʾăḏōnî</strong> — "Did I ask a son from my lord?" The verb <em>šāʾal</em> (H7592 — ask, request, demand) makes the accusation sharp: she did not request a son; Elisha volunteered the gift. Her second question — "Did I not say, Do not deceive me?" — uses <em>tašlēʾ</em> from H7952 (to mislead, throw astray). The MKT\'s "give false hope" captures the semantic range: she had warned him at the announcement not to raise hopes that would not materialize. Now she holds him to that responsibility.</p>',
    "29": '<p><strong>ḥᵃgōr mᵉtnêḵā</strong> — "gird your loins." The idiom (H2296 + H4975) means to tuck one\'s robe into the belt for rapid movement — standard preparation for urgent travel or action (1 Kgs 18:46; 2 Kgs 9:1). The staff (<em>mišʿantî</em>, H4938) is the prophet\'s distinctive implement; in Elisha\'s instruction it functions as an extension of prophetic authority, delegated to the servant. The command not to greet anyone on the road (<em>ʾim yiṣṣālᵉḵā ʾîš lōʾ tᵉḇārᵉḵennû</em>) is a formula for maximum haste — social greetings in the ancient Near East were time-consuming rituals.</p>',
    "30": '<p><strong>ḥay YHWH wᵉḥay napšeḵā</strong> — "As YHWH lives and as your soul lives." The double oath formula (H2416 × 2) with YHWH and the prophet\'s own life invoked is the strongest available oath formula in biblical Hebrew. The Shunammite binds herself to Elisha personally: she will not leave without him. Her insistence overrides the delegated authority of the staff — she knows, at some level, that the prophet\'s personal presence is required for what she needs. Elisha follows her, as Elijah followed the widow of Zarephath in an analogous crisis (1 Kgs 17).</p>',
    "31": '<p><strong>wᵉlōʾ qôl wᵉlōʾ qešeḇ</strong> — "no voice and no attention." <em>Qôl</em> (H6963 — voice, sound) and <em>qešeḇ</em> (H7182 — attentiveness, response) together describe complete non-response. The staff without the prophet produces nothing: Gehazi\'s report — "the boy has not awakened" (<em>lōʾ hēqîṣ hannāʿar</em>) — uses <em>qîṣ</em> (H6974 — awake) as a euphemism that assumes the possibility of wakening. The staff\'s failure emphasizes that the miracle requires the prophet himself, not a delegated implement.</p>',
    "32": '<p><strong>hannāʿar mēt</strong> — "the child was dead." The same unambiguous <em>māweṯ</em> (H4191) used in v20. The scene is described in two clauses: Elisha enters the house, sees the child lying dead on the bed. The detail that it is "his bed" — the prophet\'s own bed in the upper room (v21) — is maintained. The dead child on the prophet\'s bed creates the narrative tension resolved by the miracle.</p>',
    "33": '<p><strong>wayyitpallēl ʾel YHWH</strong> — "he prayed to YHWH." The verb <em>pālal</em> (H6419 — to pray, intercede) in the Hithpael appears here as the only explicit prayer in the entire miracle narrative. Elisha shuts the door (<em>sāgar</em> again, as in vv4-5), creating the private enclosure that recurs in Elisha\'s miracle-working. The prayer is not reported — only the fact of prayer. The miracle proceeds from the encounter with YHWH in private.</p>',
    "34": '<p><strong>wayyighar ʿal hayyeleḏ</strong> — "he stretched himself upon the child." The verb <em>gāḥar</em> (H1457) is a hapax legomenon — it appears only here and in 1 Kgs 18:42, where Elijah crouches with his face between his knees on Carmel. The precise posture is uncertain; the description of mouth on mouth, eyes on eyes, hands on hands suggests a full-body contact covering of the child. <em>ḥāmam</em> (H2552 — be warm, get warm) describes the flesh warming: not restored to full life yet, but the process beginning.</p>',
    "35": '<p><strong>wayyizōrēr hannāʿar šeḇaʿ pᵉʿāmîm</strong> — "the child sneezed seven times." The verb <em>zārar</em> (H2237 — to sneeze) is a hapax legomenon — it occurs only here in the entire Hebrew Bible, the unique biblical word for sneezing. The sevenfold sneezing (<em>šeḇaʿ</em> — the number of completeness) marks the full return of life: breath re-entering the body seven times. The final phrase — <em>wayyipqaḥ ʿênāyw</em>, "he opened his eyes" — uses <em>pāqaḥ</em> (H6491, to open eyes, to give sight), the same verb used for the opening of eyes at creation (Gen 3:5, 7) and healing (Isa 35:5; 42:7).</p>',
    "36": '<p><strong>qᵉrāʾ laššûnammît hazzōʾt</strong> — "Call this Shunammite." Elisha summons her through Gehazi, maintaining the mediated relationship. His instruction to her — <em>śᵉʾî binēḵ</em>, "take up your son" — uses <em>nāśāʾ</em> (H5375 — lift, carry, take up), the verb of receiving and bearing a gift.</p>',
    "37": '<p><strong>wayyiqqōd ʾarṣāh</strong> — "she bowed to the ground." The verb <em>šāḥāh</em> (H7812 — to bow down, prostrate oneself) expresses the deepest gesture of gratitude and honor; it is the same verb used for worship of YHWH and of kings. She falls at his feet, bows, and then — the final action — she <em>takes up her son and goes out</em>. The narrative resolution is complete: the child who was placed on the prophet\'s bed (v21) is now lifted (<em>nāśāʾ</em>) by his mother. The verbs of the crisis (put down, shut door) are reversed (take up, go out).</p>',
    "38": '<p><strong>rāʿāb bāʾāreṣ</strong> — "a famine in the land." The famine (<em>rāʿāb</em>, H7458) connects to the broader pattern in Kings where prophetic ministry accompanies covenant crisis (Elijah\'s drought, 1 Kgs 17). <em>wayyiṯbašal nāzîḏ</em> — "make a stew/pottage" (<em>nāzîḏ</em>, H5138 — boiled food, pottage; the same word as Esau\'s stew in Gen 25:29). The sons of the prophets sit before Elisha (<em>yōšᵉḇîm lᵉpānāyw</em>) — the posture of disciples in formal instruction.</p>',
    "39": '<p><strong>paqquʿōt śādeh</strong> — "wild gourds" (H6498 + H7704). The term <em>paqquʿōt</em> is identified by most scholars with Citrullus colocynthis (colocynth or bitter apple), a desert plant with extremely bitter, toxic fruit that causes violent intestinal distress. The gatherer is described as <em>wᵉlōʾ yāḏaʿ</em> — "not knowing what they were" — his ignorance is the narrative explanation for the crisis. The unknown toxin in the pot creates the prophetic problem of v40.</p>',
    "40": '<p><strong>māweṯ bassîr</strong> — "death in the pot!" The cry uses <em>māweṯ</em> (H4191 — death) directly: they tasted it and immediately recognized the bitterness of the colocynth. The word <em>sîr</em> (H5518 — pot, caldron) appears three times in vv38-41 — the cooking vessel becomes the site of the miracle, as cooking vessels will again in vv42-44. <em>wayyāḵlû</em> is negated — they could not eat it.</p>',
    "41": '<p><strong>qāḥ qāmaḥ</strong> — "bring flour" (<em>qemaḥ</em>, H7058 — flour, ground grain). The use of flour to neutralize the toxic stew has no natural explanation — flour does not neutralize colocynth bitterness. The action is a sign-act of prophetic authority: the prophet\'s word and the material action together accomplish what neither could accomplish separately. The narrator\'s evaluation — <em>wᵉlōʾ hāyāh dāḇār rāʿ bassîr</em>, "and there was no harmful thing in the pot" — is matter-of-fact; the miracle is stated without elaboration.</p>',
    "42": '<p><strong>bikkûrîm</strong> — "firstfruits." The man from Baal-shalishah brings <em>leḥem bikkûrîm</em> (bread of firstfruits) and <em>karmel</em> (H3759 — fresh ears of grain, new grain). <em>Bikkûrîm</em> (H1061) is the technical term for the covenant offering of the first of the harvest (Exod 23:16; Lev 2:12-14; Num 18:13) — the gift of consecrated firstfruits to the prophet mirrors the dedicated offering of the first to YHWH. The gift\'s quantity — twenty barley loaves — is insufficient for a hundred men (v43), which is the point.</p>',
    "43": '<p><strong>ʾettēn lîpnê meʾāh ʾîš</strong> — "set this before a hundred men?" The servant\'s objection restates the arithmetic problem (twenty loaves, one hundred men). Elisha\'s response — <em>kōh ʾāmar YHWH ʾāḵōl wᵉhōtēr</em>, "thus says YHWH: they shall eat and have some left over" — invokes the full authority formula of prophetic declaration: <em>kōh ʾāmar YHWH</em> (H3541 + H559 + H3068, "thus says YHWH"). The miracle is not just multiplication but the surplus that demonstrates the divine generosity exceeds exact sufficiency.</p>',
    "44": '<p><strong>wayyōtēr kidᵉḇar YHWH</strong> — "and they had leftovers, according to the word of YHWH." The <em>yōtēr</em> (H3498 — remain, leave over) is the precise fulfillment of the prophetic word in v43. The formula <em>kidᵉḇar YHWH</em> (according to the word of YHWH) closes the miracle narrative with the standard fulfillment marker. The sequence — command, objection, divine word declared, fulfillment — is the structural prototype for the NT feeding miracles (Matt 14:15-21; John 6:7-13), which deliberately echo this scene.</p>'
  },
  "5": {
    "1": '<p><strong>gibbôr ḥayil wᵉhûʾ mᵉṣōrāʿ</strong> — "a mighty man of valor — and he had leprosy." The syntax places the military honorifics first (H1368 <em>gibbôr</em>, mighty warrior; H2428 <em>ḥayil</em>, valor/force) and the disease last, as a devastating qualifier: all the greatness ends with <em>wᵉhûʾ mᵉṣōrāʿ</em> ("but he was a leper"). The word <em>ṣāraʿat</em> (H6879) covers a range of skin diseases, not necessarily what modern medicine calls leprosy (Hansen\'s disease); it is the condition that rendered one ritually impure and excluded from community (Lev 13-14). The irony is the entire verse\'s point: the man through whom YHWH had given victory to Aram is himself unable to receive victory over his own flesh.</p>',
    "2": '<p><strong>naʿărāh qᵉṭannāh</strong> — "a little girl." The double diminutive (<em>naʿărāh</em>, H5291 — young girl; <em>qāṭān</em>, H6996 — small, young) emphasizes her insignificance in social terms: a war captive, a household servant of a foreign general\'s wife. She has no name, no identity beyond her age and captive status. She is the unexpected source of the healing information — the paradigm of the lowly, unnamed instrument through whom divine provision flows. Her confidence — "he would cure him" — is stated in the conditional imperfect: <em>yēʾāsēp</em> (H622, gather/remove/take away), more literally "he would remove it from him."</p>',
    "3": '<p>The girl\'s speech uses the optative <em>lûʾ</em> (H3863 — would that/if only) + imperfect: "would that my lord were before the prophet." The conditional structure (<em>ʾāz yēʾāsēp</em>, "then he would remove") expresses confident hope, not doubt. <em>mᵉṣōrāʿtô</em> — "his leprosy" uses the Pual participle noun; the word becomes the organizing term of the entire chapter (occurs 7 times in ch. 5).</p>',
    "4": '<p>The chain of transmission — girl to mistress to Naaman to king — illustrates how divine initiative enters human political structures from the margins. The verb <em>nāgad</em> (H5046 — tell, report, declare) drives the narrative forward: it is used for both the girl\'s speech to the wife and Naaman\'s speech to the king. Information that originates with a captive child becomes a royal diplomatic initiative within two verses.</p>',
    "5": '<p><strong>ʾiggeret ʾel melek yiśrāʾēl</strong> — "a letter to the king of Israel." The king of Aram reduces the prophetic healing to a royal transaction: <em>šālaḥ sēper</em> (send a letter). The gifts Naaman carries — ten talents of silver (<em>kikkārîm</em>), six thousand shekels of gold (<em>šeqalîm</em>), and ten changes of clothing (<em>ḥᵃlîpōt bᵉgāḏîm</em>) — are diplomatic tribute scaled to the request. The enormous wealth (roughly 10 talents = ~300 kg of silver; 6,000 shekels = ~70 kg of gold) reflects how much Naaman and the king of Aram are willing to spend.</p>',
    "6": '<p>The letter says <em>wᵉʾāsaptā ʾet ṣāraʿtô</em> — "you will remove/cure his leprosy." The same verb as v2 (<em>ʾāsap</em>, H622 — gather, take away). The letter addresses the king of Israel as if he is a healer — a fundamental category error the king immediately perceives (v7). The reduction of prophetic healing to royal transaction sets up the theological critique of the entire narrative.</p>',
    "7": '<p><strong>hăʾĕlōhîm ʾānî lᵉhāmît ûlᵉhaḥᵃyôt</strong> — "Am I God, to kill and to make alive?" The king\'s theological insight is correct: the formulation <em>māmît ûmᵉḥayyeh</em> (H4191 + H2421 — kill and give life) is the exact language of Deut 32:39 ("I kill and I make alive") and 1 Sam 2:6 (Hannah\'s song). The king identifies the request as requiring divine power — he just fails to see that YHWH works through his prophet Elisha. His tearing of clothes (<em>wayyiqraʿ bᵉgāḏāyw</em>, H7167) signals the depth of perceived threat: this looks like a pretext for war.</p>',
    "8": '<p><strong>yāḏaʿ kî yēš nāḇîʾ bᵉyiśrāʾēl</strong> — "let him know that there is a prophet in Israel." Elisha\'s intervention reframes the entire situation: the king\'s role is to redirect Naaman to the prophet, not to perform the healing himself. <em>yāḏaʿ</em> (H3045 — know) in the imperfect + <em>kî</em> frames the purpose of the prophetic demonstration: Naaman will know experientially that a prophet exists in Israel. This knowing is the narrative\'s goal before the theological confession of v15.</p>',
    "9": '<p>Naaman arrives with his military equipment — <em>sûsāyw wᵉrikibbô</em> (his horses and his chariot). He stops at the door of Elisha\'s house: <em>pethah bayit ʾĕlîšāʿ</em>. The juxtaposition of military pomp and a house door is deliberate. The great man with six thousand shekels of gold stands at a prophet\'s door — the social inversion the narrative is building toward.</p>',
    "10": '<p><strong>lēḵ wᵉrāḥaṣtā šeḇaʿ pᵉʿāmîm bayardēn</strong> — "Go and wash (<em>rāḥaṣ</em>, H7364) in the Jordan seven times." Elisha sends a messenger, not himself. Two linguistic points: (1) <em>rāḥaṣ</em> (wash, bathe) is the verb in the instruction; <em>ṭāḇal</em> (dip, immerse) is the verb in v14 for what Naaman actually does — the difference between "wash yourself" and "immerse yourself" is significant; (2) <em>yardēn</em> (Jordan) is the covenant-crossing river, first named in relation to Israel\'s entry into the land (Josh 3-4). The instruction localizes the healing in the specific geography of covenant.</p>',
    "11": '<p><strong>ʾāmar ʾānî ʾāmarti</strong> — "I thought to myself." The doubled speech verb (<em>ʾāmar</em> + <em>ʾānî ʾāmarti</em>, H559) marks Naaman\'s angry internal monologue. He expected: Elisha to come out (<em>yāṣōʾ yēṣēʾ</em>, imperfect emphatic — "he would surely come out"), to stand before him (<em>wᵉʿāmaḏ</em>), to call on the name of YHWH, and to wave his hand (<em>wᵉhēnîp yāḏô</em>, H5130 — wave, brandish) over the affected place. The expected ritual is dramatic, public, and involves direct contact — everything Elisha\'s actual instruction lacks. Naaman\'s expectations are precisely wrong.</p>',
    "12": '<p><strong>hᵃlōʾ ṭôḇ... mikkōl mê yiśrāʾēl</strong> — "Are not [these rivers] better than all the waters of Israel?" <em>ṭôḇ</em> (H2895 — good, better) is the same evaluative term used throughout Genesis for creation. Naaman\'s argument is logical on its own terms: the rivers of Damascus (Abana/Amana and Pharpar) are large, clear rivers — demonstrably "better" as rivers than the Jordan, which is muddy and unremarkable. His question uses the same verb <em>rāḥaṣ</em> (wash) that Elisha used: "could I not wash in them and be clean?" The answer the narrative gives is: yes, but not for Naaman, not now, not for this purpose.</p>',
    "13": '<p><strong>ʾāḇî</strong> — "my father." Naaman\'s servants address him with the term of intimate respect normally used for a father or a highly regarded elder. Their logic is irrefutable: if Elisha had commanded something difficult (<em>dāḇār gāḏôl</em> — a great/difficult word), Naaman would have done it. <em>raq</em> (H7535 — only, merely, just) emphasizes the smallness of the actual request: "how much more should you comply when he merely says: wash and be clean." The <em>raq</em> identifies Naaman\'s resistance as inversely proportional to the simplicity of the command.</p>',
    "14": '<p><strong>wayyiṭbōl bᵉyardēn šeḇaʿ pᵉʿāmîm</strong> — "he dipped himself in the Jordan seven times." The verb here is <em>ṭāḇal</em> (H2881 — to dip, immerse, plunge into), not <em>rāḥaṣ</em> (wash) that Elisha commanded. Naaman does not merely wash but immerses. <em>wᵉyāšāḇ bᵉśārô</em> — "his flesh was restored" uses <em>šûḇ</em> (H7725 — return, turn back, restore) in the Qal imperfect: the flesh literally "returned" or "turned back" — not just healed but restored to its original condition. The comparison — <em>kᵉḇaśar naʿar qāṭōn</em>, "like the flesh of a little child" — uses the same phrase (<em>naʿar qāṭōn</em>) as the servant girl of v2. The little girl and the restored little-child flesh bracket the narrative.</p>',
    "15": '<p><strong>yāḏaʿtî kî ʾên ʾĕlōhîm bᵉḵol hāʾāreṣ kî ʾim bᵉyiśrāʾēl</strong> — "I know that there is no God in all the earth except in Israel." The verb <em>yāḏaʿ</em> (H3045 — know) is now in the perfect: Naaman knows, has come to know. His monotheistic confession uses <em>kî ʾim</em> (H3588 + H518 — except, only) — the exclusive statement. His offer of a <em>bᵉrāḵāh</em> (H1293 — blessing, gift) to Elisha uses the covenant word for blessing; the "blessing" offered is the gift brought from Damascus. He presents what he brought as a gift of gratitude, using the beautiful ambiguity of the word that means both divine blessing and a material gift.</p>',
    "16": '<p><strong>ḥay YHWH ʾăšer ʿāmadtî lᵉpānāyw</strong> — "As YHWH lives, before whom I stand." Elisha\'s refusal is sworn by the same oath formula used by Elijah (1 Kgs 17:1; 18:15). The phrase <em>ʿāmadtî lᵉpānāyw</em> (I stand before him) identifies Elisha as a courtier of YHWH — one who serves at the divine court. The refusal of the gift is theologically grounded: to accept payment would imply that the healing was a human service rather than a divine grace. <em>wayyipṣar</em> (H6484 — to urge strongly, press) — Naaman pressed him, but Elisha refused.</p>',
    "17": '<p><strong>ʾădāmāh</strong> (H127 — ground, soil, earth) — two mule-loads of <em>ʾădāmāh</em>. The choice of <em>ʾădāmāh</em> rather than <em>ʾereṣ</em> (land, territory, H776) is significant: <em>ʾădāmāh</em> is the fertile, life-giving soil — the word of Gen 2:7 where YHWH forms the human from the <em>ʾădāmāh</em>. Naaman wants Israel\'s covenant soil to stand on when he worships YHWH. His theological reasoning — "your servant will offer burnt offering and sacrifice to no other god but YHWH" — reflects the ancient assumption that gods inhabit specific territories; his request is to bring Israel\'s sacred ground into Aram so that his worship of YHWH has a legitimate substrate.</p>',
    "18": '<p><strong>sᵉlaḥ nā lᵉʿaḇdᵉḵā</strong> — "pardon your servant." The verb <em>sālaḥ</em> (H5545 — forgive, pardon) is the specific word for divine forgiveness, used almost exclusively with YHWH as subject in the OT (Num 14:19-20; 1 Kgs 8:30ff). Naaman directs this vocabulary to Elisha as mediator. The <em>Rimmôn</em> temple (H7417 — the Aramean storm god, cognate with Hadad) creates the political dilemma: Naaman must physically support the king when he bows in the pagan temple. His request — <em>wᵉhištaḥᵃwîtî</em> (and I bow down, H7812 — twice in this verse) — is honest about what he must do while declaring where his actual allegiance lies. The tension between bodily conformity and interior conviction is a genuine theological problem to which Elisha gives no rebuke.</p>',
    "19": '<p><strong>lēḵ lᵉšālôm</strong> — "Go in peace." Elisha\'s send-off uses the standard Hebrew farewell formula but with the full weight of <em>šālôm</em>: wholeness, covenant completion. He makes no ruling on the Rimmon question; the silence is the answer. The brevity of his response — two words — after the theological complexity of vv17-18 is itself significant: the prophet does not legislate what Naaman must do in the Aramean court. The grace given is not conditional on perfect circumstances.</p>',
    "20": '<p><strong>wayyōʾmer gēḥăzî naʿar ʾĕlîšāʿ</strong> — "Gehazi, the servant (<em>naʿar</em>) of Elisha, said to himself." The internal monologue (<em>wᵉhûʾ nāʾamar</em>, literally "and he said [to himself]") follows the pattern of Naaman\'s internal speech in v11. Gehazi\'s rationalization uses the same oath formula as Elisha in v16 (<em>ḥay YHWH</em>) — he swears by YHWH to commit a sin against YHWH\'s intent. <em>rûṣ ʾaḥᵃrāyw</em> (H7323 + H310 — run after him) — the verb of urgency that the Shunammite used in urgent faith (4:25) is here used in urgent greed.</p>',
    "21": '<p>Naaman sees Gehazi running after him (<em>rāṣ ʾaḥᵃrāyw</em>) and descends from his chariot — a sign of respect to Elisha\'s representative. The question <em>hăšālôm</em> — "is everything well?" — echoes the šālôm language of ch. 4. His response to what he perceives as the prophet\'s servant in legitimate service is warm and immediate.</p>',
    "22": '<p><strong>šālôm</strong> — Gehazi\'s use of the peace-formula is the opposite of the Shunammite\'s: she used it as a statement of faith in adverse circumstances; he uses it as a deceptive opener for a fraudulent request. The lie is elaborate: two sons of the prophets, hill country of Ephraim, a talent of silver and two changes of clothing. The request is modest (compared to Naaman\'s original gift) — which makes it more plausible. Gehazi uses Elisha\'s name and authority (<em>ʾǎdōnî šᵉlāḥanî</em>, "my master has sent me") falsely.</p>',
    "23": '<p><strong>hôʾel qah šᵉnê kikkārîm</strong> — "please accept two talents." Naaman insists on more than asked — he doubles the amount, pressing (<em>pāraṣ</em>, H6555 — urge, press, insist) Gehazi to take two talents. He binds the silver in two bags and hands them to his own servants to carry before Gehazi. The generous Gentile gives twice what the fraudulent Israelite requested.</p>',
    "24": '<p>At the hill (<em>hāʿōpel</em>, H6077 — a steep mound, specifically used of the citadel area in Samaria; cf. 2 Kgs 5:24 and Mic 1:5) Gehazi takes the goods from Naaman\'s servants and hides them in the house. The verb <em>pāqad</em> (H6485 — attend to, set in place) used here for storing the goods contrasts with the open exchange of the previous verses. The concealment is the basis for the lie to Elisha in v25.</p>',
    "25": '<p><strong>ʾānāh hālaḵtā gēḥăzî</strong> — "Where did you go, Gehazi?" The question is a test — Elisha already knows (v26). Gehazi\'s denial — <em>lōʾ hālaḵ ʿaḇdᵉḵā ʾānāh wᵉʾānāh</em>, "your servant has not gone here or there" — uses the indefinite doubling of <em>ʾānāh wᵉʾānāh</em> (H575 × 2) for "anywhere at all." The absolute denial makes the lie complete.</p>',
    "26": '<p><strong>lōʾ libbî hālaḵ ʾittᵉḵā</strong> — "Did not my heart go with you?" The noun <em>lēḵ</em> (from <em>lāḵaḵ</em>? No — this is <em>lēḇ</em>, H3820, heart/mind) — "was not my heart going with you?" — is a claim to prophetic awareness of Gehazi\'s journey. Elisha\'s heart (mind/perception) tracked Gehazi\'s movements in real time. The question <em>hāʿēt lāqaḥat</em> — "is this the time to take/receive?" — uses the <em>ʿēt</em> (H6256 — time, season, appointed time) of covenantal opportunity: there is a right time and a wrong time; this was the wrong time for a monetary transaction that would commercialize divine grace.</p>',
    "27": '<p><strong>wᵉṣāraʿat naʿᵃmān tiḏbaq bᵉḵā</strong> — "the leprosy of Naaman will cling (<em>dāḇaq</em>, H1692) to you." The verb <em>dāḇaq</em> is the strongest Hebrew verb for adhesion, attachment, and covenant loyalty: it describes Ruth clinging to Naomi (Ruth 1:14), the covenant command to "hold fast" to YHWH (Deut 11:22; 13:5), and marital union (Gen 2:24). The irony is complete: the verb that describes unbreakable covenant devotion to YHWH is now used for the unbreakable punishment that will attend Gehazi and his descendants forever (<em>lᵉʿôlām</em>). What should have clung to him (covenant loyalty) did not; what should not cling to him (Naaman\'s leprosy) now will — forever. Gehazi goes out from Elisha\'s presence leprous, "white as snow" (<em>mᵉṣōrāʿ kaššāleg</em>) — the same snow-white appearance as Moses\'s temporary leprous condition (Exod 4:6) and Miriam\'s punishment (Num 12:10), but for Gehazi, permanent.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '2kings')
    merge_comm(existing, KINGS2)
    save_comm('mkt-original', '2kings', existing)
    print('2 Kings 4–5 mkt-original written.')

if __name__ == '__main__':
    main()
